      },
      {
        "from": "User Registration Flow",
        "to": "KYC Verification Service",
        "status": "risk",
        "issue": "Registration is hard-blocked on KYC completion. No async or deferred verification path exists. Users cannot proceed at all if Onfido is slow or down, turning an external dependency outage into a total registration outage."
      }
    ],
    "contract_compliance": "Onfido API contract appears correctly consumed. However, the service makes no provision for Onfido returning degraded responses, partial failures, or rate-limiting (HTTP 429). Only the happy path and total failure (503) are accounted for.",
    "data_flow_integrity": "Data flows synchronously: registration request → Onfido API call → response → registration outcome. No queuing or persistence of in-flight KYC requests means any failure mid-flight loses the attempt entirely with no automatic retry or recovery."
  },

  "observability_review": {
    "logging": {
      "coverage": "adequate",
      "gaps": [
        "No mention of logging Onfido response latency per-request for tail-latency debugging",
        "No mention of logging Onfido error response bodies for root-cause analysis during incidents"
      ]
    },
    "metrics": {
      "coverage": "Baseline metrics exist (kyc_checks_total, kyc_duration_histogram) but critical operational metrics are missing",
      "gaps": [
        "No error-rate metric broken out by Onfido HTTP status code (4xx vs 5xx)",
        "No metric tracking consecutive Onfido failures (needed for circuit-breaker-like alerting)",
        "No metric for in-flight/queued KYC requests to detect saturation",
        "No SLI metric tracking registration success rate against the 99.95% target"
      ]
    },
    "tracing": {
      "coverage": "Not mentioned — unclear if distributed tracing spans are propagated through the Onfido call",
      "gaps": [
        "No trace context mentioned for correlating a user registration request end-to-end through KYC",
        "On-call engineer at 3am cannot trace a specific user's failed registration through the Onfido hop without this"
      ]
    },
    "debugging_capability": "Partial. Structured JSON logging and basic metrics provide a floor. However, an on-call engineer investigating 'why are registrations failing?' would need to manually correlate logs and metrics — no trace IDs, no Onfido-error-specific dashboards, and no way to distinguish 'Onfido is slow' from 'Onfido is down' from metrics alone."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Onfido API is completely down",
        "handling": "unhandled",
        "recommendation": "MUST-HAVE: Implement a circuit breaker (e.g., 5 failures in 30s → open for 60s). When open, return a clear 'KYC pending' status and allow registration to proceed in a limited/provisional state. Process KYC asynchronously when Onfido recovers. This is the single highest-priority gap."
